// Port of legacy parseKey() from the original Castia Market codebase.
// Strips variant hashes, tier suffixes, PUA glyphs, normalizes whitespace,
// and applies title case.

const LOWER_WORDS = new Set([
  "a", "an", "the", "and", "but", "or", "for", "nor", "on", "at", "to",
  "by", "in", "of", "up", "as", "vs", "via",
]);

const MITHRIL_SETS = [
  "prismatic", "daydream", "athanasia", "saprophyte", "phezar", "azertuan",
  "vurgohk", "vertigo", "oldus", "kayran", "llanakin", "erphis", "hulia",
  "halgrabind", "elven", "aerondight", "serpent", "paragon", "igru", "curtana",
  "requinox", "stellaris", "celestia",
];

// Knowledge Cap / Christmas Cap are special gear sets that come in 6 stat
// modifier variants (Hunting, Mining, Woodcutting, Fishing, Farming,
// Smelting). The modifier is appended to the base name, so the raw key
// looks like 'knowledge cap hunting' and the display name should be
// 'Knowledge Cap' with a separate 'Hunting' modifier tag.
const CAP_BASES = ["knowledge cap", "christmas cap"];
const CAP_MODIFIERS = [
  "hunting", "mining", "woodcutting", "fishing", "farming", "smelting",
];

const GEAR_SUFFIXES = new Set([
  "helmet", "chestplate", "leggings", "boots",
  "sword", "axe", "pickaxe", "shovel", "hoe",
  "fishing rod", "bow", "crossbow", "shield",
  "rod",
]);

export function tierClass(tier) {
  if (tier === 1) return "text-emerald-400";
  if (tier === 2) return "text-amber-400";
  if (tier === 3) return "text-red-400";
  return "text-zinc-400";
}

function titleCase(str) {
  if (!str) return str;
  return str
    .split(" ")
    .map((w, i) => {
      const wl = w.toLowerCase();
      if (/^(?=[ivxlcdm]+$)[ivxlcdm]+$/i.test(w)) return w.toUpperCase();
      if (i > 0 && LOWER_WORDS.has(wl)) return wl;
      return wl.charAt(0).toUpperCase() + wl.slice(1);
    })
    .join(" ");
}

// Strip Private-Use-Area glyphs (Castia in-game font icons) and normalize whitespace
function stripPUA(s) {
  if (!s) return "";
  return s
    .replace(/[\uE000-\uF8FF]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

export function parseItemKey(raw) {
  if (!raw) {
    return { displayName: "—", category: "misc", tier: 0, modifiers: [], rawKey: raw };
  }

  let baseKey = String(raw).trim();
  let tier = 0;

  // Strip variant hash
  const variantMatch = baseKey.match(/\|v:([^|]+)$/i);
  if (variantMatch) {
    baseKey = baseKey.slice(0, baseKey.lastIndexOf("|v:")).trim();
  }

  // Strip Prismatic / set tier suffix
  const tierMatch = baseKey.match(/\|t([123])$/i);
  if (tierMatch) {
    tier = parseInt(tierMatch[1], 10);
    baseKey = baseKey.slice(0, baseKey.lastIndexOf("|t")).trim();
  }

  const kl = baseKey.toLowerCase();

  // BOOKS — strip "book:" prefix, drop PUA glyphs, normalize whitespace
  if (kl.startsWith("book:")) {
    const after = baseKey.replace(/^book:\s*/i, "");
    const cleaned = stripPUA(after).replace(/^[^\w(]+/, "").trim();
    return {
      displayName: "Book: " + titleCase(cleaned),
      category: "Enchanted Book",
      tier: 0,
      modifiers: [],
      rawKey: raw,
    };
  }

  // MITHRIL SETS — every set now embeds the (T1)/(T2)/(T3) suffix in
  // the name (Prismatic included); the T1/T2/T3 colored badge is still
  // rendered as a separate UI tag in cards and the detail drawer.
  for (const setName of MITHRIL_SETS) {
    if (kl === setName || kl.startsWith(setName + " ")) {
      const remainder = kl.slice(setName.length).trim();
      const lastWord = remainder.split(" ").pop();
      if (
        remainder === "" ||
        GEAR_SUFFIXES.has(remainder) ||
        GEAR_SUFFIXES.has(lastWord)
      ) {
        let display = titleCase(stripPUA(baseKey));
        if (tier > 0) {
          display += ` (T${tier})`;
        }
        return {
          displayName: display,
          category: "Set Gear",
          tier,
          modifiers: [],
          rawKey: raw,
        };
      }
    }
  }

  // KNOWLEDGE CAP / CHRISTMAS CAP — strip the modifier from the name
  // and return it as a separate tag. The modifier can appear in two
  // shapes depending on the source feed:
  //   1. bracket:  "knowledge cap [farming]"     (castia-worker)
  //   2. trailing: "knowledge cap farming"        (older API shape)
  for (const capBase of CAP_BASES) {
    if (kl === capBase || kl.startsWith(capBase + " ")) {
      const remainder = kl.slice(capBase.length).trim();
      // Shape 1: bracket — strip "[ ... ]" and read inner word
      const bracketMatch = remainder.match(/^\[\s*([a-z]+)\s*\]$/);
      if (bracketMatch) {
        const mod = CAP_MODIFIERS.find((m) => m === bracketMatch[1]);
        if (mod) {
          return {
            displayName: titleCase(capBase),
            category: "Set Gear",
            tier: 0,
            modifiers: [titleCase(mod)],
            rawKey: raw,
          };
        }
      }
      // Shape 2: trailing word
      const mod = CAP_MODIFIERS.find((m) => remainder === m);
      if (mod) {
        return {
          displayName: titleCase(capBase),
          category: "Set Gear",
          tier: 0,
          modifiers: [titleCase(mod)],
          rawKey: raw,
        };
      }
    }
  }

  // Fallback — clean + title case
  return {
    displayName: titleCase(stripPUA(baseKey)),
    category: null,
    tier,
    modifiers: [],
    rawKey: raw,
  };
}

// Number formatter matching the legacy fmt()
// Reads default format from module-level setter so preferences flow globally.
let _defaultFormat = "compact";

export function setPriceFormat(f) {
  _defaultFormat = f;
}

export function fmt(n, format) {
  if (n == null || n === "") return "—";
  const v = +n;
  if (Number.isNaN(v)) return "—";
  const f = format || _defaultFormat;
  if (f === "full") return Math.round(v).toLocaleString();
  if (v >= 1e9) return (v / 1e9).toFixed(2) + "B";
  if (v >= 1e6) return (v / 1e6).toFixed(2) + "M";
  if (v >= 1e3) return (v / 1e3).toFixed(1) + "K";
  return v.toLocaleString();
}

export function fmtFull(n) {
  return n == null ? "—" : Math.round(n).toLocaleString();
}

// Cleans up an enchantment key for display: drops the "minecraft:" prefix,
// replaces underscores/dashes with spaces, then title-cases. Mirrors the
// legacy `enchantmentLabel()` from data.js. Used in the detail drawer so
// "minecraft:sharpness" renders as "Sharpness" and "fire_aspect" as
// "Fire Aspect".
export function enchantmentLabel(name) {
  const clean = String(name || "")
    .replace(/^minecraft:/i, "")
    .replace(/[_-]+/g, " ")
    .trim();
  return clean ? titleCase(clean) : "";
}

export function fmtTime(ms) {
  if (!ms) return "—";
  const diff = (Date.now() - ms) / 1000;
  if (diff < 10) return "just now";
  if (diff < 60) return Math.floor(diff) + "s ago";
  if (diff < 3600) return Math.floor(diff / 60) + "m ago";
  if (diff < 86400) return Math.floor(diff / 3600) + "h ago";
  return Math.floor(diff / 86400) + "d ago";
}
