import { Clock } from "lucide-react";
import { fmtTime } from "@/lib/parseItem";

// Color-coded freshness pill used wherever a snapshot or trail timestamp
// is rendered. The thresholds match the staleness buckets the rest of
// the app uses for the "stale data" banner (1h/24h/7d) so a green dot
// always means "this is safe to trust" and a red one means "check
// before you act."
//
// Props:
//   ms        - last-updated timestamp in ms (number) or 0/null.
//   prefix    - small text before the relative time (e.g. "Updated").
//   showIcon  - whether to show the clock icon (default true).
//   size      - "xs" | "sm" (default "sm"). Controls font size.
export default function FreshnessPill({ ms, prefix = "Updated", showIcon = true, size = "sm" }) {
  if (!ms) return null;
  const ageMs = Date.now() - ms;
  const ageHours = ageMs / (1000 * 60 * 60);
  // Buckets: green < 1h, amber 1-24h, red > 24h, gray when unknown.
  let dotClass = "bg-zinc-500";
  let labelClass = "text-zinc-400";
  if (ageHours < 1) { dotClass = "bg-emerald-400"; labelClass = "text-emerald-300"; }
  else if (ageHours < 24) { dotClass = "bg-amber-400"; labelClass = "text-amber-300"; }
  else if (ageHours < 168) { dotClass = "bg-red-400"; labelClass = "text-red-300"; }
  else { dotClass = "bg-zinc-600"; labelClass = "text-zinc-500"; }

  const sizeClasses = size === "xs"
    ? "text-[9px] tracking-[0.18em] gap-1"
    : "text-[10px] tracking-[0.18em] gap-1.5";

  return (
    <span
      data-testid="freshness-pill"
      data-age-bucket={ageHours < 1 ? "fresh" : ageHours < 24 ? "ok" : "stale"}
      className={`inline-flex items-center font-mono uppercase ${sizeClasses} ${labelClass}`}
    >
      <span className={`inline-block w-1.5 h-1.5 rounded-full ${dotClass}`} />
      {showIcon && <Clock className="w-3 h-3" />}
      <span>{prefix} {fmtTime(ms)}</span>
    </span>
  );
}
