import { useEffect, useMemo, useRef, useCallback } from "react";
import { useSearchParams, useNavigate } from "react-router-dom";
import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
import {
  X, ShieldCheck, Shield, ShieldAlert, ShieldX, ArrowUpRight, ArrowLeft, BellOff,
} from "lucide-react";
import { useMarket, pushRecentlyViewed } from "@/lib/MarketContext";
import { useBlocklist } from "@/lib/useBlocklist";
import ItemDetailContent from "./ItemDetailContent";
import ShopDetailPanel from "./ShopDetailPanel";
import Breadcrumb from "@/components/ui/Breadcrumb";

// ---------- shared atoms ----------

const LABEL_STYLES = {
  Trustworthy: { icon: ShieldCheck, color: "text-emerald-400", bg: "bg-emerald-500/10", border: "border-emerald-500/30" },
  Neutral: { icon: Shield, color: "text-zinc-400", bg: "bg-white/[0.04]", border: "border-white/10" },
  Suspicious: { icon: ShieldAlert, color: "text-amber-400", bg: "bg-amber-500/10", border: "border-amber-500/30" },
  Flagged: { icon: ShieldX, color: "text-red-400", bg: "bg-red-500/10", border: "border-red-500/30" },
};

// ---------- SellerPanel ----------

function SellerPanel({ sellerName, onClose, onFilterListings }) {
  const { sellers, market } = useMarket();
  const blocklist = useBlocklist();
  const isBlocked = blocklist.has(sellerName);
  const navigate = useNavigate();
  const seller = useMemo(
    () => sellers?.find((s) => s.name === sellerName) || null,
    [sellers, sellerName]
  );

  if (!seller) {
    return (
      <div className="p-10">
        <div className="font-heading text-xl font-bold mb-2">{sellerName}</div>
        <p className="font-mono text-xs text-zinc-500">Seller not in current dataset.</p>
        <button
          onClick={() => onFilterListings(sellerName)}
          data-testid="seller-view-listings"
          className="mt-6 inline-flex items-center gap-2 bg-emerald-500 hover:bg-emerald-400 text-black font-bold uppercase tracking-[0.18em] text-[11px] px-4 py-2.5 rounded-sm"
        >
          Search listings <ArrowUpRight className="w-3.5 h-3.5" />
        </button>
      </div>
    );
  }

  const label = seller.isBlacklisted ? "Flagged" : (seller.accuracyLabel || "Neutral");
  const style = LABEL_STYLES[label] || LABEL_STYLES.Neutral;
  const Icon = style.icon;
  const markup = seller.avgMarkupPercent;
  const isBedrock = seller.identityKey?.startsWith("bedrock");

  return (
    <div className="flex flex-col h-full">
        <div className="sticky top-0 z-10 bg-bg-base/95 backdrop-blur-xl border-b border-white/10 px-6 sm:px-8 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <button
              onClick={() => navigate(-1)}
              data-testid="seller-back"
              aria-label="Back"
              className="inline-flex items-center gap-1.5 border border-white/15 hover:border-emerald-500 hover:text-emerald-400 text-zinc-300 font-bold uppercase tracking-[0.18em] text-[10px] px-2.5 py-1 rounded-sm transition-colors"
            >
              <ArrowLeft className="w-3 h-3" /> Back
            </button>
            <Breadcrumb
              items={[
                { label: "Home", href: "/" },
                { label: "Sellers", href: "/sellers" },
                { label: seller.name },
              ]}
              color="text-amber-400"
              className="mb-0 text-[10px]"
            />
          </div>
          <button onClick={onClose} data-testid="drawer-close" aria-label="Close" className="p-2 text-zinc-400 hover:text-white transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>
      <div className="flex-1 overflow-y-auto custom-scrollbar">
        <div className="relative px-6 sm:px-8 pt-8 pb-6">
          <div className={`absolute -top-32 -right-20 w-96 h-96 ${style.bg} blur-[100px] rounded-full pointer-events-none`}></div>
          <div className="relative flex items-start gap-5">
            {!isBedrock ? (
              <img
                src={`https://render.crafty.gg/3d/bust/${encodeURIComponent(seller.name)}`}
                alt=""
                width={88}
                height={88}
                className="rounded-lg bg-white/[0.05] shrink-0"
                onError={(e) => { e.currentTarget.style.visibility = "hidden"; }}
              />
            ) : (
              <div className="w-22 h-22 rounded-lg bg-white/[0.05] border border-white/10 grid place-items-center text-zinc-500 font-mono uppercase shrink-0">
                {seller.name.slice(0,2)}
              </div>
            )}
            <div className="min-w-0 flex-1">
              <h2 className="font-heading text-3xl sm:text-4xl tracking-tighter font-black leading-tight break-words">
                {seller.name}
              </h2>
              <div className="mt-1 font-mono text-[11px] text-zinc-500">
                {isBedrock ? "Bedrock" : seller.uuid ? `Java · ${seller.uuid.slice(0, 8)}` : "—"}
              </div>
              <div className={`mt-3 inline-flex items-center gap-1.5 ${style.bg} ${style.border} border rounded-full px-2.5 py-1`}>
                <Icon className={`w-3 h-3 ${style.color}`} />
                <span className={`font-mono text-[10px] uppercase tracking-wider ${style.color}`}>{label}</span>
              </div>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-2 sm:grid-cols-3 gap-px bg-white/10 border-y border-white/10">
          <KPI l="Total listings" v={seller.totalListings} />
          <KPI l="Markup" v={`${markup > 0 ? "+" : ""}${markup.toFixed(1)}%`} c={markup > 15 ? "text-red-400" : markup < -10 ? "text-emerald-400" : "text-white"} />
          <KPI l="Overpriced" v={`${seller.overpricedRatio.toFixed(1)}%`} />
        </div>

        <div className="p-6 sm:p-8 space-y-6">
          <div>
            <div className="font-mono text-[10px] uppercase tracking-[0.25em] text-zinc-500 mb-2">About this rating</div>
            <p className="text-zinc-400 text-sm leading-relaxed">
              {label === "Trustworthy" && "This seller consistently lists at or below the market median. A safe bet."}
              {label === "Neutral" && "This seller's listings hover near market median — neither great nor concerning."}
              {label === "Suspicious" && "This seller frequently lists items above the market median. Verify prices before buying."}
              {label === "Flagged" && "This seller has been flagged by the community. Trade with extreme caution."}
            </p>
          </div>

          <button
            data-testid="seller-view-listings"
            onClick={() => onFilterListings(seller.name)}
            className="group w-full inline-flex items-center justify-between gap-3 bg-emerald-500/10 hover:bg-emerald-500/20 border border-emerald-500/30 hover:border-emerald-500/60 text-emerald-300 hover:text-emerald-200 font-bold uppercase tracking-[0.18em] text-xs px-5 py-4 rounded-sm transition-all"
          >
            <span>View their listings in detail</span>
            <ArrowUpRight className="w-4 h-4 group-hover:translate-x-0.5 group-hover:-translate-y-0.5 transition-transform" />
          </button>

          <button
            data-testid="seller-block-toggle"
            onClick={() => blocklist.toggle(seller.name)}
            className={`group w-full inline-flex items-center justify-between gap-3 border font-bold uppercase tracking-[0.18em] text-xs px-5 py-4 rounded-sm transition-all ${
              isBlocked
                ? "bg-red-500/10 hover:bg-red-500/20 border-red-500/30 hover:border-red-500/60 text-red-300 hover:text-red-200"
                : "bg-zinc-800/50 hover:bg-zinc-700/50 border-white/10 hover:border-white/20 text-zinc-300 hover:text-white"
            }`}
          >
            <span>{isBlocked ? "Unblock seller" : "Block this seller"}</span>
            <BellOff className="w-4 h-4" />
          </button>

          {market && (
            <div className="text-center font-mono text-[10px] uppercase tracking-wider text-zinc-500">
              Currently {market.stats.totalItems} items tracked across the market.
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

function KPI({ l, v, c = "text-white" }) {
  return (
    <div className="bg-bg-base px-4 py-4">
      <div className="font-mono text-[9px] uppercase tracking-[0.25em] text-zinc-500 mb-1">{l}</div>
      <div className={`font-heading text-xl font-bold tabular ${c}`}>{v}</div>
    </div>
  );
}

// ---------- DetailDrawer (the universal shell) ----------
//
// Listens for ?item=<key> (item preview) and ?sellerView=<name>
// (seller preview) on the current URL and slides in a panel with
// the corresponding content. Both modes coexist; the user can
// switch from an item to a seller (via the trail) without leaving
// the current page.
//
// The drawer is mounted once at the App level so any page can
// trigger it via openItem() / openSellerInDrawer() without needing
// to know about the shell.

export default function DetailDrawer() {
  const [searchParams, setSearchParams] = useSearchParams();
  const navigate = useNavigate();
  const itemKey = searchParams.get("item");
  const sellerName = searchParams.get("sellerView");
  const shopItem = searchParams.get("shopItem");
  const isOpen = !!(itemKey || sellerName || shopItem);
  const previousFocusRef = useRef(null);
  const drawerRef = useRef(null);
  const prefersReduced = useReducedMotion();

  const close = useCallback(() => {
    const next = new URLSearchParams(searchParams);
    next.delete("item");
    next.delete("sellerView");
    next.delete("shopItem");
    setSearchParams(next, { replace: true });
  }, [searchParams, setSearchParams]);

  const closeRef = useRef(close);
  useEffect(() => { closeRef.current = close; }, [close]);

  const openSeller = (name) => {
    const next = new URLSearchParams(searchParams);
    next.delete("item");
    next.delete("shopItem");
    next.set("sellerView", name);
    setSearchParams(next);
  };

  const filterListings = (name) => {
    close();
    navigate(`/listings?seller=${encodeURIComponent(name)}`);
  };

  // ESC to close + lock scroll + focus management while open
  useEffect(() => {
    if (!isOpen) return;

    previousFocusRef.current = document.activeElement;

    const handler = (e) => { if (e.key === "Escape") closeRef.current(); };
    document.addEventListener("keydown", handler);

    // Initial focus on the drawer panel after animation
    requestAnimationFrame(() => {
      const closeBtn = document.querySelector('[data-testid="drawer-close"]');
      if (closeBtn) closeBtn.focus();
    });

    const prev = document.body.style.overflow;
    document.body.style.overflow = "hidden";

    return () => {
      document.removeEventListener("keydown", handler);
      document.body.style.overflow = prev;
      previousFocusRef.current?.focus();
    };
  }, [isOpen]);

  // Focus trap: keep Tab cycling inside the drawer while open
  useEffect(() => {
    if (!isOpen) return;
    const drawer = drawerRef.current;
    if (!drawer) return;
    const onKeyDown = (e) => {
      if (e.key !== "Tab") return;
      const focusable = drawer.querySelectorAll(
        'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])',
      );
      if (focusable.length === 0) return;
      const first = focusable[0];
      const last = focusable[focusable.length - 1];
      if (e.shiftKey) {
        if (document.activeElement === first) {
          e.preventDefault();
          last.focus();
        }
      } else {
        if (document.activeElement === last) {
          e.preventDefault();
          first.focus();
        }
      }
    };
    document.addEventListener("keydown", onKeyDown);
    return () => document.removeEventListener("keydown", onKeyDown);
  }, [isOpen]);

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          <motion.div
            key="backdrop"
            initial={prefersReduced ? undefined : { opacity: 0 }}
            animate={prefersReduced ? undefined : { opacity: 1 }}
            exit={prefersReduced ? undefined : { opacity: 0 }}
            transition={{ duration: 0.25 }}
            onClick={close}
            data-testid="drawer-backdrop"
            className="fixed inset-0 z-50 drawer-backdrop"
          />
          <motion.aside
            ref={drawerRef}
            key="drawer"
            initial={prefersReduced ? undefined : { x: "100%" }}
            animate={prefersReduced ? undefined : { x: 0 }}
            exit={prefersReduced ? undefined : { x: "100%" }}
            transition={{ duration: 0.45, ease: [0.16, 1, 0.3, 1] }}
            data-testid="detail-drawer"
            className="fixed top-0 right-0 bottom-0 z-50 w-full sm:w-[min(680px,92vw)] bg-bg-base border-l border-white/10 shadow-[-30px_0_80px_rgba(0,0,0,0.6)] flex flex-col"
            role="dialog"
            aria-modal="true"
            aria-label={itemKey ? "Item detail" : sellerName ? "Seller detail" : shopItem ? "Chest shop detail" : "Detail panel"}
          >
            {shopItem ? (
              <ShopDetailPanel itemName={shopItem} onClose={close} onOpenSeller={openSeller} />
            ) : itemKey ? (
              <ItemDetailContent itemKey={itemKey} onClose={close} onOpenSeller={openSeller} />
            ) : sellerName ? (
              <SellerPanel sellerName={sellerName} onClose={close} onFilterListings={filterListings} />
            ) : null}
          </motion.aside>
        </>
      )}
    </AnimatePresence>
  );
}

// Convenience helpers for opening the drawer from anywhere
export function openItem(searchParams, setSearchParams, itemKey) {
  const next = new URLSearchParams(searchParams);
  next.delete("sellerView");
  next.set("item", itemKey);
  setSearchParams(next);
  
  // Record this view in recently viewed
  pushRecentlyViewed(itemKey);
}
export function openSellerInDrawer(searchParams, setSearchParams, name) {
  const next = new URLSearchParams(searchParams);
  next.delete("item");
  next.delete("shopItem");
  next.set("sellerView", name);
  setSearchParams(next);
}
export function openShopDetail(searchParams, setSearchParams, itemName) {
  const next = new URLSearchParams(searchParams);
  next.delete("item");
  next.delete("sellerView");
  next.set("shopItem", itemName);
  setSearchParams(next);
}
