import { aborter } from "./aborter";

const BASE_URL =
  process.env.REACT_APP_CASTIA_WORKER_URL ||
  "https://castia-worker.lektodesigns.workers.dev";

const DEFAULT_TIMEOUT_MS = 10000;

// P3-4: Worker endpoints have internal TTLs, so we don't need a browser cache
// but we should avoid redundant inflight requests.
const inflight = new Map();

async function workerFetch(endpoint, { signal } = {}) {
  const url = `${BASE_URL}${endpoint}`;
  
  if (inflight.has(url)) return inflight.get(url);

  const combined = aborter(DEFAULT_TIMEOUT_MS, signal);
  const promise = (async () => {
    try {
      const res = await fetch(url, {
        headers: { Accept: "application/json" },
        signal: combined.signal,
      });
      if (!res.ok) {
        let body;
        try { body = await res.json(); } catch { body = null; }
        const message = body?.error || body?.message || `HTTP ${res.status}`;
        const err = new Error(message);
        err.status = res.status;
        err.retryable = res.status === 429 || res.status >= 500;
        err.endpoint = endpoint;
        err.body = body;
        throw err;
      }
      return res.json();
    } finally {
      combined.cleanup();
      inflight.delete(url);
    }
  })();

  inflight.set(url, promise);
  return promise;
}

export function fetchPrices({ signal } = {}) {
  return workerFetch("/prices", { signal });
}

export function fetchSellers({ signal } = {}) {
  return workerFetch("/sellers", { signal });
}

export function fetchAuctions(itemQuery, { signal } = {}) {
  return workerFetch(`/auctions?item=${encodeURIComponent(itemQuery)}`, { signal });
}

export function fetchSellerAuctions(sellerName, { limit = 100, cursor = null, signal } = {}) {
  const params = new URLSearchParams({
    seller: sellerName,
    limit: String(limit),
  });
  if (cursor) params.set("cursor", cursor);
  return workerFetch(`/seller-auctions?${params.toString()}`, { signal });
}

export function fetchChestShops({ item, seller, limit, tier, set, signal } = {}) {
  const params = new URLSearchParams();
  if (item) params.set("item", item);
  if (seller) params.set("seller", seller);
  if (limit) params.set("limit", String(limit));
  if (tier) params.set("tier", tier);
  if (set) params.set("set", set);
  const qs = params.toString();
  return workerFetch(`/chest-shops${qs ? `?${qs}` : ""}`, { signal });
}

export function fetchStock({ item, seller, server, limit, freshWithinHours, signal } = {}) {
  const params = new URLSearchParams();
  if (item) params.set("item", item);
  if (seller) params.set("seller", seller);
  if (server) params.set("server", server);
  if (limit) params.set("limit", String(limit));
  if (freshWithinHours) params.set("freshWithinHours", String(freshWithinHours));
  const qs = params.toString();
  return workerFetch(`/stock${qs ? `?${qs}` : ""}`, { signal });
}

export function fetchWarpZones({ server, dimension, owner, limit, signal } = {}) {
  const params = new URLSearchParams();
  if (server) params.set("server", server);
  if (dimension) params.set("dimension", dimension);
  if (owner) params.set("owner", owner);
  if (limit) params.set("limit", String(limit));
  const qs = params.toString();
  return workerFetch(`/warp-zones${qs ? `?${qs}` : ""}`, { signal });
}
