import { useEffect, useRef, useState, useCallback } from "react";
import { RefreshCw, X } from "lucide-react";
import { motion, AnimatePresence, useReducedMotion } from "framer-motion";
import { APP_VERSION } from "@/version";

const CHECK_INTERVAL_MS = 5 * 60 * 1000;
const DISMISS_KEY = "castia.updateDismissed";
const REFRESH_COOLDOWN_KEY = "castia.lastRefresh";
const REFRESH_COOLDOWN_MS = 30_000; // 30 second cooldown after manual refresh

function getLastRefreshTime() {
  try {
    const stored = sessionStorage.getItem(REFRESH_COOLDOWN_KEY);
    return stored ? parseInt(stored, 10) : 0;
  } catch {
    return 0;
  }
}

function setLastRefreshTime() {
  try {
    sessionStorage.setItem(REFRESH_COOLDOWN_KEY, String(Date.now()));
  } catch { /* ignore */ }
}

function isInRefreshCooldown() {
  return Date.now() - getLastRefreshTime() < REFRESH_COOLDOWN_MS;
}

export default function VersionPrompt() {
  const [needsUpdate, setNeedsUpdate] = useState(false);
  const [latestVersion, setLatestVersion] = useState(null);
  const [updateSource, setUpdateSource] = useState(null); // 'sw' | 'http'
  const [dismissed, setDismissed] = useState(false);

  // Use refs to avoid stale closures in async callbacks
  const dismissedRef = useRef(false);
  const waitingWorkerRef = useRef(null);
  const registrationRef = useRef(null);
  const isRefreshingRef = useRef(false);

  const updateDismissed = useCallback((val) => {
    setDismissed(val);
    dismissedRef.current = val;
    try {
      if (val) sessionStorage.setItem(DISMISS_KEY, APP_VERSION);
      else sessionStorage.removeItem(DISMISS_KEY);
    } catch { /* ignore */ }
  }, []);

  const prefersReduced = useReducedMotion();

  // Initialize dismissed state from sessionStorage
  useEffect(() => {
    try {
      const isDismissed = sessionStorage.getItem(DISMISS_KEY) === APP_VERSION;
      updateDismissed(isDismissed);
    } catch { /* ignore */ }
  }, [updateDismissed]);

  // Service Worker update detection
  useEffect(() => {
    if (typeof navigator === "undefined" || !("serviceWorker" in navigator)) return;
    if (process.env.NODE_ENV !== "production") return;
    // Skip if we're in cooldown from a recent manual refresh
    if (isInRefreshCooldown()) return;

    const setupRegistration = async () => {
      try {
        const reg = await navigator.serviceWorker.getRegistration();
        if (!reg) return;
        registrationRef.current = reg;

        // Already waiting when we mount
        if (reg.waiting && !dismissedRef.current) {
          waitingWorkerRef.current = reg.waiting;
          setNeedsUpdate(true);
          setUpdateSource("sw");
        }

        // Watch for new installations
        reg.addEventListener("updatefound", () => {
          const installing = reg.installing;
          if (!installing) return;
          installing.addEventListener("statechange", () => {
            if (installing.state === "installed" && reg.waiting && !dismissedRef.current) {
              waitingWorkerRef.current = reg.waiting;
              setNeedsUpdate(true);
              setUpdateSource("sw");
            }
          });
        });

        // Handle controller change (worker took over)
        const onControllerChange = () => {
          // Clear update state when a new worker takes control
          waitingWorkerRef.current = null;
          setNeedsUpdate(false);
          setUpdateSource(null);
        };
        navigator.serviceWorker.addEventListener("controllerchange", onControllerChange);
      } catch { /* SW registration failed, fall through to HTTP check */ }
    };

    setupRegistration();
  }, []);

  // HTTP version polling (fallback when no SW)
  useEffect(() => {
    // Skip if SW update is already handling this, or we're in refresh cooldown
    if (needsUpdate || isInRefreshCooldown()) return;

    let cancelled = false;
    const check = async () => {
      try {
        // Use no-store to bypass cache, add timestamp to prevent CDN caching
        const res = await fetch(
          `${process.env.PUBLIC_URL || ""}/version.json?_=${Date.now()}`,
          { cache: "no-store", credentials: "omit" }
        );
        if (!res.ok || cancelled) return;

        const j = await res.json();
        if (cancelled) return;

        setLatestVersion(j.version || null);

        // Only show HTTP-based update if SW hasn't caught it
        const isStale = j.version && j.version !== APP_VERSION && !dismissedRef.current;
        if (isStale && !needsUpdate) {
          setNeedsUpdate(true);
          setUpdateSource("http");
        } else if (j.version === APP_VERSION && updateSource === "http") {
          // Version caught up, clear the stale notification
          setNeedsUpdate(false);
          setUpdateSource(null);
        }
      } catch { /* network error, ignore */ }
    };

    check();
    const t = setInterval(check, CHECK_INTERVAL_MS);
    return () => { cancelled = true; clearInterval(t); };
  }, [needsUpdate, updateSource]);

  // Apply update: posts SKIP_WAITING to SW then reloads
  const applyUpdate = useCallback(() => {
    if (isRefreshingRef.current) return;
    isRefreshingRef.current = true;

    setLastRefreshTime();

    if (waitingWorkerRef.current) {
      waitingWorkerRef.current.postMessage({ type: "SKIP_WAITING" });
    }

    // Use replace + cache-busting to ensure fresh load
    const url = new URL(window.location.href);
    url.searchParams.set("_v", Date.now());
    window.location.replace(url.toString());
  }, []);

  // Dismiss update for this session (per version)
  const dismiss = useCallback(() => {
    updateDismissed(true);
  }, [updateDismissed]);

  // Don't render if no update needed or dismissed
  if (!needsUpdate || dismissed) return null;

  // Unified design: single consistent notification
  const isSW = updateSource === "sw";
  const borderColor = isSW ? "border-emerald-500/30" : "border-amber-500/30";
  const bgAccent = isSW ? "bg-emerald-500/15" : "bg-amber-500/15";
  const iconColor = isSW ? "text-emerald-400" : "text-amber-400";
  const btnColor = isSW
    ? "bg-emerald-500 hover:bg-emerald-400 text-black"
    : "bg-amber-500 hover:bg-amber-400 text-black";

  const content = (
    <div
      data-testid="update-prompt"
      role="status"
      className={`fixed bottom-4 left-4 right-4 z-[55] max-w-sm mx-auto bg-bg-base/95 backdrop-blur-xl border ${borderColor} rounded-2xl p-3 shadow-2xl`}
    >
      <div className="flex items-center gap-3">
        <div className={`shrink-0 w-8 h-8 rounded-lg ${bgAccent} grid place-items-center`}>
          <RefreshCw className={`w-3.5 h-3.5 ${iconColor}`} />
        </div>
        <div className="flex-1 min-w-0">
          <div className="font-heading font-bold text-xs uppercase tracking-[0.18em] text-white">
            {isSW ? "Update available" : "New version deployed"}
          </div>
          <p className="text-zinc-400 text-[11px] leading-snug mt-0.5">
            {isSW
              ? "A new version of Castia is ready."
              : `Refresh to get the latest version${latestVersion ? ` (${latestVersion})` : ""}.`}
          </p>
        </div>
        <button
          data-testid="update-prompt-reload"
          onClick={applyUpdate}
          className={`shrink-0 ${btnColor} font-bold uppercase tracking-[0.18em] text-[10px] px-3 py-1.5 rounded-sm transition-colors`}
        >
          Reload
        </button>
        <button
          onClick={dismiss}
          aria-label="Dismiss"
          className="shrink-0 text-zinc-500 hover:text-white transition-colors p-1"
        >
          <X className="w-3.5 h-3.5" />
        </button>
      </div>
    </div>
  );

  if (prefersReduced) return content;

  return (
    <AnimatePresence>
      <motion.div
        key="update-prompt"
        initial={{ opacity: 0, y: 16 }}
        animate={{ opacity: 1, y: 0 }}
        exit={{ opacity: 0, y: 16 }}
        transition={{ duration: 0.3 }}
      >
        {content}
      </motion.div>
    </AnimatePresence>
  );
}
